        &:hover {
          background: linear-gradient(135deg, #667eea, #764ba2);
          color: #fff;
          border-color: transparent;
          box-shadow: 0 2px 8px rgba(102, 126, 234, 0.35);
        }
      }
    }

    .name {
      margin: 0 0 6px;
